const PhotoPost = ({ photo, text, comments }) => {
    return (
        <div className="photo-post">
            <img src={photo} alt="Post" />
            <p>{text}</p>
            <div className="comments">
            <h3>Comments</h3>
            <ul>
                {comments.map((comment, index) => (
                <li key={index}>{comment}</li>
                ))}
            </ul>
            </div>
        </div>
    );
};

export default PhotoPost;
